// Pact Broker webhook configuration (sent via API or pactflow UI)
{
  "events": [
    { "name": "contract_content_changed" },
    { "name": "contract_published_with_content_that_requires_verification" }
  ],
  "request": {
    "method": "POST",
    "url": "https://api.github.com/repos/myorg/genai-service/dispatches",
    "headers": {
      "Content-Type": "application/json",
      "Authorization": "Bearer ${user.githubToken}"
    },
    "body": {
      "event_type": "pact-changed",
      "client_payload": {
        "pact_url": "${pactbroker.pactUrl}",
        "consumer_name": "${pactbroker.consumerName}",
        "consumer_version": "${pactbroker.consumerVersionNumber}"
      }
    }
  }
}
